        switch (Code) {
            else => {
                return PPC_PRED_INVALID;
            },
            @as(ppc_pred, PPC_PRED_LT), @as(ppc_pred, PPC_PRED_LT_MINUS), @as(ppc_pred, PPC_PRED_LT_PLUS), @as(ppc_pred, PPC_PRED_LT_RESERVED) => {
